                            # Score N.0 = level N (Nth challenge completed)
                            level_for_storage = int(game_state.score)
                            
                            # ================================================================
                            # BUG FIX (2024-12-03): Use CUMULATIVE capture for L2+
                            # ================================================================
                            # PROBLEM: "level_X_win" triggered level-specific capture, which
